def warn_on_large_delete(result)
  deletes = result.counts.fetch(:deleted, 0) + result.counts.fetch(:deleted_local, 0)
  return if deletes < LARGE_DELETE_WARNING

  @logger.warn("[Sync] large delete: #{deletes} records removed in one run")
end

